import { useEffect, useState } from 'react';
import { Button, Form, Table } from 'react-bootstrap';
import api from '../api/client';

export default function TicketList({ readOnly = false, developerView = false }) {
  const [tickets, setTickets] = useState([]);
  const [filters, setFilters] = useState({ search: '', status: '' });

  const fetchTickets = async () => {
    const { data } = await api.get('/tickets/', { params: { search: filters.search, status: filters.status || undefined } });
    setTickets(data);
  };

  useEffect(() => { fetchTickets(); }, []);

  const exportExcel = () => {
    const params = new URLSearchParams();
    if (filters.search) params.append('search', filters.search);
    if (filters.status) params.append('status', filters.status);
    window.open(`${process.env.REACT_APP_API_BASE_URL || 'http://localhost:8000/api'}/tickets/export_excel/?${params.toString()}`, '_blank');
  };

  const developerUpdate = async (id, status) => {
    await api.post(`/tickets/${id}/developer_update/`, { status });
    fetchTickets();
  };

  return (
    <>
      <div className="d-flex gap-2 mb-3">
        <Form.Control placeholder="Search by ticket / subject" value={filters.search} onChange={(e) => setFilters({ ...filters, search: e.target.value })} />
        <Form.Select value={filters.status} onChange={(e) => setFilters({ ...filters, status: e.target.value })}>
          <option value="">All Status</option>
          <option>Resolved by Support</option>
          <option>Sent to Developer</option>
          <option>Developer In Progress</option>
          <option>Closed</option>
        </Form.Select>
        <Button onClick={fetchTickets}>Apply</Button>
        <Button variant="success" onClick={exportExcel}>Export Excel</Button>
      </div>
      <Table bordered hover responsive>
        <thead>
          <tr>
            <th>Ticket ID</th><th>Module</th><th>Submodule</th><th>Subject</th><th>Status</th><th>Decision</th><th>Created</th>{developerView && <th>Action</th>}
          </tr>
        </thead>
        <tbody>
          {tickets.map((ticket) => (
            <tr key={ticket.id}>
              <td>{ticket.ticket_id}</td>
              <td>{ticket.department_name || ''}</td>
              <td>{ticket.module_name}</td>
              <td>{ticket.submodule_name}</td>
              <td>{ticket.subject}</td>
              <td>{ticket.status}</td>
              <td>{ticket.support_decision}</td>
              <td>{new Date(ticket.created_at).toLocaleString()}</td>
              {developerView && (
                <td>
                  {!readOnly && (
                    <div className="d-flex gap-2">
                      <Button size="sm" onClick={() => developerUpdate(ticket.id, 'Developer In Progress')}>Mark In Progress</Button>
                      <Button size="sm" variant="success" onClick={() => developerUpdate(ticket.id, 'Closed')}>Close</Button>
                    </div>
                  )}
                </td>
              )}
            </tr>
          ))}
        </tbody>
      </Table>
    </>
  );
}
